#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
struct node
{
	ll a,b;
	bool operator<(const node other) const
	{
		return b>other.b;
	}
} a[2005],b[2005];
ll n,ans,c1,c2,c3;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>c1>>c2>>c3;
	for(int i=1;i<=n;i++) 
	{
		cin>>a[i].a>>a[i].b;
	}
	for(int i=1;i<=n;i++)
	{
		int cnt=0;
		for(int j=1;j<=n;j++)
		{
			if(a[j].a<a[i].a) continue;
			ll tmp=a[j].b-(c3-(a[j].a-a[i].a)*c1)/c2;
			if(tmp<=a[j].b) b[++cnt]=node{tmp,a[j].b};
		}
		priority_queue<int> pq;
		sort(b+1,b+1+cnt);
		int num=0;
		for(int j=1;j<=cnt;j++,num++)
		{
			ans=max(ans,(ll)num);
			while(!pq.empty()&&pq.top()>b[j].b)
			{
				num--;
				pq.pop();
			}
			pq.push(b[j].a);
		}
		ans=max(ans,(ll)num);
	}
	cout<<ans;
	return 0;
}
